import{_ as t,c as r,l as e,a as o,t as i,a4 as n,o as l}from"./chunks/framework.CzsDe1xi.js";const P=JSON.parse('{"title":"常用注解","description":"","frontmatter":{"title":"常用注解"},"headers":[],"relativePath":"doc/编程语言/后端/Java/业务框架/Spring/常用注解.md","filePath":"packages/doc/src/编程语言/后端/Java/业务框架/Spring/常用注解.md","lastUpdated":1711637456000}'),p={name:"doc/编程语言/后端/Java/业务框架/Spring/常用注解.md"},s={id:"frontmatter-title",tabindex:"-1"},h=e("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),d=n('<h2 id="bean" tabindex="-1">@Bean <a class="header-anchor" href="#bean" aria-label="Permalink to &quot;@Bean&quot;">​</a></h2><p>用在方法上，将当前方法的返回值对象放到容器当中！可以理解为前者是由spring自动创建对象，而@Bean创建对象是交给我们自己来控制。</p><p>@Bean一般出现在方法上面，也可用于自定义注解上</p><h2 id="component" tabindex="-1">@Component <a class="header-anchor" href="#component" aria-label="Permalink to &quot;@Component&quot;">​</a></h2><p>该注解用于将一个类标识为组件（Component）。它是通用的注解，表示一个普通的 Spring 组件。被 @Component 注解标记的类将由 Spring 自动扫描并注册为 Bean，可通过依赖注入等方式使用。</p><h2 id="repository" tabindex="-1">@Repository <a class="header-anchor" href="#repository" aria-label="Permalink to &quot;@Repository&quot;">​</a></h2><p>该注解用于将一个类标识为数据访问层组件（Repository）。通常用于与数据库交互的类，封装了数据访问逻辑。被 @Repository 注解标记的类通常配合其他注解如 @Autowired 进行依赖注入，提供持久化数据的操作。</p><h2 id="controller" tabindex="-1">@Controller <a class="header-anchor" href="#controller" aria-label="Permalink to &quot;@Controller&quot;">​</a></h2><p>该注解用于将一个类标识为控制器层组件（Controller）。通常用于接收请求、处理业务逻辑，并返回视图或数据给客户端。被 @Controller 注解标记的类可以通过 @RequestMapping 或其他相关注解定义请求映射和处理方法。</p><h2 id="service" tabindex="-1">@Service <a class="header-anchor" href="#service" aria-label="Permalink to &quot;@Service&quot;">​</a></h2><p>该注解用于将一个类标识为服务层组件（Service）。通常用于实现业务逻辑的类，可以封装具体的业务操作。被 @Service 注解标记的类通常与 @Repository 注解标记的类配合使用，通过依赖注入调用数据访问层的方法，提供业务服务。</p><h2 id="value" tabindex="-1">@Value <a class="header-anchor" href="#value" aria-label="Permalink to &quot;@Value&quot;">​</a></h2><p>用于注入值到属性或方法参数中。可以通过 SpEL（Spring 表达式语言）进行动态赋值。</p><h2 id="qualifier" tabindex="-1">@Qualifier <a class="header-anchor" href="#qualifier" aria-label="Permalink to &quot;@Qualifier&quot;">​</a></h2><p>与 @Autowired 注解一起使用，用于指定具体的依赖对象的名称，解决依赖注入时的歧义性。</p><h2 id="responsebody" tabindex="-1">@ResponseBody <a class="header-anchor" href="#responsebody" aria-label="Permalink to &quot;@ResponseBody&quot;">​</a></h2><p>用于将方法的返回值直接作为响应体返回给客户端，常用于 RESTful 接口的实现。</p><h2 id="requestparam" tabindex="-1">@RequestParam <a class="header-anchor" href="#requestparam" aria-label="Permalink to &quot;@RequestParam&quot;">​</a></h2><p>用于将请求参数绑定到方法的参数上。</p><h2 id="requestmapping" tabindex="-1">@RequestMapping <a class="header-anchor" href="#requestmapping" aria-label="Permalink to &quot;@RequestMapping&quot;">​</a></h2><p>用于映射 HTTP 请求到方法或控制器类上，定义请求的 URL、HTTP 方法、请求参数等。 类似的还有@GetMapping @PostMapping @PutMapping @DeleteMapping @PatchMapping等</p>',21);function c(a,u,m,_,q,f){return l(),r("div",null,[e("h1",s,[o(i(a.$frontmatter.title)+" ",1),h]),d])}const g=t(p,[["render",c]]);export{P as __pageData,g as default};
